=== global settings.json hooks block ===
{
  "PreToolUse": [
    {
      "matcher": "Agent",
      "hooks": [
        {
          "type": "command",
          "command": "$HOME/.claude/hooks/skill-intake-gate-check.sh"
        },
        {
          "type": "command",
          "command": "$HOME/.claude/hooks/autonomy-grant-dispatch-prompt-check.sh"
        }
      ]
    },
    {
      "matcher": "Write|Edit",
      "hooks": [
        {
          "type": "command",
          "command": "$HOME/.claude/hooks/closure-discipline-signal-check.sh"
        },
        {
          "type": "command",
          "command": "$HOME/.claude/hooks/signal-recorder-silent-check.sh"
        }
      ]
    },
    {
      "matcher": "mcp__scheduled-tasks__create_scheduled_task|mcp__scheduled-tasks__update_scheduled_task",
      "hooks": [
        {
          "type": "command",
          "command": "$HOME/.claude/hooks/forge-shim-gate-check.sh"
        }
      ]
    },
    {
      "matcher": "mcp__google-workspace__.*",
      "hooks": [
        {
          "type": "command",
          "command": "$HOME/.claude/hooks/native-connector-precedence-check.sh"
        }
      ]
    },
    {
      "matcher": "Bash",
      "hooks": [
        {
          "type": "command",
          "command": "$HOME/.claude/hooks/venv-guard-pretooluse-check.sh"
        }
      ]
    }
  ],
  "PostToolUse": [
    {
      "matcher": "Write|Edit",
      "hooks": [
        {
          "type": "command",
          "command": "source ~/.claude/hooks/helpers/product-paths.sh && if echo \"$CLAUDE_TOOL_INPUT\" | grep -qF \"$FORGE_OUTPUTS_CLAUDE_CODE\"; then bash \"$FORGE_ENGINE_SCRIPTS/count-check.sh\"; fi"
        },
        {
          "type": "command",
          "command": "$HOME/.claude/hooks/cast-yaml-validate.sh"
        },
        {
          "type": "command",
          "command": "if echo \"$CLAUDE_TOOL_INPUT\" | python3 -c \"import sys,json; inp=json.load(sys.stdin); path=inp.get('file_path',''); exit(0 if '.intent/signals/' in path or '.intent/decisions/' in path else 1)\" 2>/dev/null; then python3 \"$HOME/Workspaces/Core/products/org-design-tooling/src/frontmatter-writethrough.py\"; fi"
        }
      ]
    }
  ],
  "SessionStart": [
    {
      "matcher": "*",
      "hooks": [
        {
          "type": "command",
          "command": "~/.claude/hooks/autonomy-grant-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/closure-discipline-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/overwatch-staleness-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/overwatch-nested-init-check.sh"
        },
        {
          "type": "command",
          "command": "python3 \"$HOME/Workspaces/Core/products/loom/hooks/loom_session_start.py\"",
          "timeout": 10,
          "statusMessage": "Loom: priming sibling-session context"
        },
        {
          "type": "command",
          "command": "$HOME/Workspaces/Core/products/quartermaster/hooks/quartermaster-tick.sh",
          "timeout": 10,
          "statusMessage": "Quartermaster: ticking the work queue"
        }
      ]
    }
  ],
  "SessionEnd": [
    {
      "matcher": "*",
      "hooks": [
        {
          "type": "command",
          "command": "python3 \"$HOME/Workspaces/Core/products/loom/hooks/loom_session_end.py\"",
          "timeout": 10,
          "statusMessage": "Loom: sealing session thread"
        }
      ]
    }
  ],
  "Stop": [
    {
      "matcher": "*",
      "hooks": [
        {
          "type": "command",
          "command": "~/.claude/hooks/autonomy-grant-stop-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/autonomy-posture-check-layer-4.2.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/closure-discipline-stop-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/link-format-stop-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/emdash-stop-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/presend-assertion-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/engagement-signal-cadence-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/forge-signal-cadence-stop-check.sh"
        },
        {
          "type": "command",
          "command": "~/.claude/hooks/session-end.sh"
        }
      ]
    }
  ]
}

